import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it)); D = int(next(it))
        if A + B + C <= D:
            out.append('1')
        elif A + B <= D:
            out.append('2')
        else:
            out.append('3')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

